// COMPLETE, COMPILABLE C code
#include <stdio.h>
#define MOD 1000000007
int dp[51][51][2];
int solve(int p, int q, int N, int B1, int B2, int S1, int S2) {
    for (int i = 0; i <= p; i++) {
        for (int j = 0; j <= q; j++) {
            dp[i][j][0] = dp[i][j][1] = 0;
        }
    }
    dp[0][0][0] = dp[0][0][1] = 1;
    for (int i = 0; i <= p; i++) {
        for (int j = 0; j <= q; j++) {
            for (int k = 0; k < 2; k++) {
                if (k == 0) {
                    for (int s = 1; s <= S1 && s <= i; s++) {
                        if (i - s >= 0 && j >= 0) {
                            dp[i - s][j][1] = (dp[i - s][j][1] + dp[i][j][k]) % MOD;
                        }
                    }
                } else {
                    for (int s = 1; s <= S2 && s <= j; s++) {
                        if (i >= 0 && j - s >= 0) {
                            dp[i][j - s][0] = (dp[i][j - s][0] + dp[i][j][k]) % MOD;
                        }
                    }
                }
            }
        }
    }
    int ans = 0;
    for (int i = 0; i <= p; i++) {
        for (int j = 0; j <= q; j++) {
            if (i + j == N) {
                ans = (ans + dp[i][j][0] + dp[i][j][1]) % MOD;
            }
        }
    }
    return ans;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int p, q, N, B1, B2, S1, S2;
        scanf("%d %d %d", &p, &q, &N);
        scanf("%d %d", &B1, &B2);
        scanf("%d %d", &S1, &S2);
        printf("%d\n", solve(p, q, N, B1, B2, S1, S2));
    }
    return 0;
}

